import { FC, useEffect } from 'react';

import { formatPrice } from '#components/ProductComparisonCommon/helpers/formatPrice';

import ProductCarouselCard from './ProductCarouselCard';
import { LazyProductCardProps } from './ProductCarouselCard.types';

const LazyProductCarouselCard: FC<LazyProductCardProps> = (props) => {
  const { id, endpoint, prettyPrice } = props.product;

  const {
    fetchPrice,
    isComparison,
    isFetched,
    isLoading,
    isVisible,
    livePrice,
    product,
    selectedItemIDs,
    toggleSelectedProduct,
    vendorLinkUpdated,
  } = props;

  useEffect(() => {
    if (isVisible && !isLoading && !isFetched) {
      fetchPrice(id, endpoint);
    }
  }, [isVisible, endpoint, id, isLoading, isFetched, fetchPrice]);

  return (
    <ProductCarouselCard
      product={product}
      isComparison={isComparison}
      isLoading={isLoading}
      price={formatPrice(livePrice || prettyPrice)}
      selectedItemIDs={selectedItemIDs}
      toggleSelectedProduct={toggleSelectedProduct}
      vendorLinkUpdated={vendorLinkUpdated}
    />
  );
};

export default LazyProductCarouselCard;
