import { useCallback, FC } from 'react';

import { INITIAL_INDEX } from '#components/Carousel/Carousel.constants';
import { LazyProductCarouselCard } from '#components/ProductCarouselCard';
import { Product } from '#components/ProductComparisonCommon/types';

import {
  NextButton,
  PrevButton,
  Wrapper,
  StyledCarousel,
} from './ProductCarousel.styles';
import {
  ProductCarouselProps,
  DefaultRenderSlideCallback,
} from './ProductCarousel.types';
import ProductCarouselSlide from './ProductCarouselSlide';
import Title from './Title';

import ChevronLeftSVG from '#icons/chevron-left-solid-24.svg';
import ChevronRightSVG from '#icons/chevron-right-solid-24.svg';

type ButtonProps = {
  disabled: boolean;
  onClick: () => void;
};

/**
 * @explain
 * ButtonPrev and ButtonNext are used in render props for StyledCarousel.
 * This is because the underlying carousel tries not to be opinionated about
 * styling.
 */

const ButtonPrev: FC<ButtonProps> = ({ disabled, onClick }) => (
  <PrevButton
    svg={ChevronLeftSVG}
    isDisabled={disabled}
    size="large"
    onClick={onClick}
  ></PrevButton>
);

const ButtonNext: FC<ButtonProps> = ({ disabled, onClick }) => (
  <NextButton
    svg={ChevronRightSVG}
    isDisabled={disabled}
    size="large"
    onClick={onClick}
  ></NextButton>
);

const ProductCarousel: FC<ProductCarouselProps> = ({
  fetchPrice,
  initialIndex = INITIAL_INDEX,
  isComparison,
  livePrices,
  products,
  selectedItemIDs = [],
  title,
  dispatchers,
}) => {
  // called from Carousel
  const renderSlide = useCallback<DefaultRenderSlideCallback>(
    ({ slideIndex, item, isVisible, ref }) => {
      // cast necessary as Carousel doesn't use Typescript
      const product = item as Product;
      const livePrice = livePrices.find(
        (livePrice) => livePrice.id === item.id,
      );

      return (
        <ProductCarouselSlide key={`item-${slideIndex}`} ref={ref}>
          <LazyProductCarouselCard
            fetchPrice={fetchPrice}
            isComparison={isComparison}
            isFetched={(livePrice && livePrice.fetched) || false}
            isLoading={(livePrice && livePrice.loading) || false}
            livePrice={(livePrice && livePrice.price) || ''}
            vendorLinkUpdated={(livePrice && livePrice.link) || ''}
            isVisible={isVisible}
            product={product}
            selectedItemIDs={selectedItemIDs}
            toggleSelectedProduct={dispatchers.toggleSelectedProduct}
          />
        </ProductCarouselSlide>
      );
    },
    [selectedItemIDs, livePrices, fetchPrice, isComparison, dispatchers],
  );

  // className is necessary as Carousel requires it and not possible to make property optional
  return (
    <Wrapper>
      {title && <Title>{title}</Title>}

      <StyledCarousel
        className=""
        initialIndex={initialIndex}
        ButtonPrev={ButtonPrev}
        ButtonNext={ButtonNext}
        increment={2}
        items={products}
        renderSlide={renderSlide}
      />
    </Wrapper>
  );
};

export default ProductCarousel;
