import { forwardRef, ReactNode } from 'react';

import { Item } from './ProductCarousel.styles';

type Props = {
  children: ReactNode;
};

const ProductCarouselSlide = forwardRef<HTMLDivElement, Props>(
  function ProductCarouselSlide({ children }, ref) {
    return <Item ref={ref}>{children}</Item>;
  },
);

export default ProductCarouselSlide;
