/**
 * @explain
 * mocks the PageState context
 * specifically for ProductComparison at the moment, so requires to be extended for other components
 */

import { FC, createContext, useState } from 'react';

import {
  PageState,
  Dispatchers,
  LivePrice,
  ContextState,
} from '../types/PageContext';

const calculateSelectedItems = (selectedItems: string[], id: string) => {
  if (selectedItems.includes(id)) {
    return selectedItems.filter((itemId) => itemId !== id);
  } else {
    return [...selectedItems, id];
  }
};

const initialState: PageState = {
  defaultState: {
    bookmarkModalOpen: false,
    drawerLoginOpen: false,
    galleryIndex: 0,
    drawerMenuOpen: false,
    galleryOpen: false,
    returnFocus: '',
  },
  productComparison: {
    selectedItems: [],
    showModal: false,
  },
  productPrices: [] as LivePrice[],
};

const initialDispatchers: Dispatchers = {
  /* Product */
  clearProductSelection: () => {},
  hideProductModal: () => {},
  showProductModal: () => {},
  toggleSelectedProduct: () => {},

  /* Bookmark */
  closeBookmarkModal: () => {},
  toggleBookmarkModal: () => {},

  /* Drawer */
  closeDrawerLogin: () => {},
  closeDrawerMenu: () => {},
  toggleDrawerLoginOpen: () => {},
  toggleDrawerMenuOpen: () => {},

  /* Gallery */
  toggleGalleryOpen: () => {},

  /* Product Price */
  setProductPrice: () => {},
  setProductPriceIsFetched: () => {},
  setProductPriceIsLoading: () => {},
};

export const PageContext = createContext({
  ...initialState,
  dispatchers: initialDispatchers,
});

export const PageContextDecorator = (Story: FC) => {
  const [pageState, setPageState] = useState(initialState);

  const setProductPriceIsFetched = (id: string) => {
    setPageState((state) => {
      if (state.productPrices.find((productPrice) => productPrice.id === id)) {
        return {
          ...state,
          productPrices: state.productPrices.map((productPrice) => {
            if (productPrice.id === id) {
              return {
                ...productPrice,
                loading: false,
                fetched: true,
              };
            }

            return productPrice;
          }),
        };
      }

      return state;
    });
  };

  const setProductPriceIsLoading = (id: string) => {
    setPageState((state) => {
      if (state.productPrices.find((productPrice) => productPrice.id === id)) {
        return {
          ...state,
          productPrices: state.productPrices.map((productPrice) => {
            if (productPrice.id === id) {
              return {
                ...productPrice,
                loading: true,
              };
            }

            return productPrice;
          }),
        };
      } else {
        return {
          ...state,
          productPrices: [
            ...state.productPrices,
            {
              id,
              loading: true,
              price: '',
              fetched: false,
              link: '',
            },
          ],
        };
      }
    });
  };

  const setProductPrice = (id: string, price: string, link: string) => {
    setPageState((state) => {
      if (state.productPrices.find((productPrice) => productPrice.id === id)) {
        return {
          ...state,
          productPrices: state.productPrices.map((productPrice) => {
            if (productPrice.id === id) {
              return {
                ...productPrice,
                link,
                price,
              };
            }

            return productPrice;
          }),
        };
      } else {
        return {
          ...state,
          productPrices: [
            ...state.productPrices,
            {
              id,
              loading: false,
              price,
              fetched: true,
              link,
            },
          ],
        };
      }
    });
  };

  const showProductModal = () => {
    setPageState((state) => ({
      ...state,
      productComparison: {
        ...state.productComparison,
        showModal: true,
      },
    }));
  };

  const hideProductModal = () => {
    setPageState((state) => ({
      ...state,
      productComparison: {
        ...state.productComparison,
        showModal: false,
      },
    }));
  };

  const toggleSelectedProduct = (id: string) => {
    setPageState((state) => {
      return {
        ...state,
        productComparison: {
          ...state.productComparison,
          selectedItems: calculateSelectedItems(
            state.productComparison.selectedItems,
            id,
          ),
        },
      };
    });
  };

  const clearProductSelection = () => {
    setPageState((state) => ({
      ...state,
      productComparison: {
        ...state.productComparison,
        selectedItems: [],
      },
    }));
  };

  const contextState: ContextState = {
    ...pageState,
    dispatchers: {
      ...initialDispatchers,
      clearProductSelection,
      hideProductModal,
      setProductPrice,
      setProductPriceIsFetched,
      setProductPriceIsLoading,
      showProductModal,
      toggleSelectedProduct,
    },
  };

  return (
    <div>
      <PageContext.Provider value={contextState}>
        <Story />
      </PageContext.Provider>
    </div>
  );
};
